-- Enrichment marathon batch: bup, Burnermail, Buttondown, C-Dogs SDL, C3, Cabot, Cacheflow, CacheFly

-- ── bup ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$bup is a free, open-source backup program that stores data using git's packfile format, giving it fast incremental backups and global block-level deduplication across and within files. Created by developer Avery Pennarun (also known for sshuttle, git-subtree, and Tailscale) and first released around 2010, bup was built to solve a problem plain git could not: efficiently version-controlling very large files such as virtual machine disk images and multi-gigabyte databases. Instead of git's diff-based storage, bup splits files into content-defined chunks using a rolling checksum (similar to rsync), then writes those chunks directly into packfiles without a separate garbage-collection or repacking step, so it stays fast even as backup sets grow into hundreds of gigabytes or more. Because the underlying format is git-compatible, backed-up data can, in principle, be inspected with ordinary git tooling even without bup itself. bup supports local and remote backups over SSH, FUSE-based mounting of backup snapshots, indexing of millions of filenames, and optional par2 redundancy for bit-rot protection, making it a favorite among sysadmins, self-hosters, and command-line-oriented Linux and BSD users who want a scriptable, dependency-light alternative to commercial backup suites.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Open-source project maintained by volunteer contributors (no formal company)$q$, company_size),
  headquarters = COALESCE($q$N/A - distributed open-source project$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$bup Review: The Free, Git-Based Backup Tool for Huge Files$q$, seo_title),
  seo_meta_description = COALESCE($q$bup is a free open-source backup program built on git's packfile format. See how its rolling-checksum deduplication handles VM images and huge datasets.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$bup is a free, open-source, command-line backup program that repurposes git's packfile storage format to deliver fast incremental backups with global deduplication. It was created by Avery Pennarun, a prolific open-source developer also known for sshuttle, git-subtree, redo, and later for co-founding Tailscale, and bup's development began around 2010, with the project being accepted into Debian the same year. The core problem bup solves is one plain git struggles with: efficiently tracking very large binary files, such as virtual machine disk images or multi-gigabyte database dumps, where git's normal diff-based model becomes slow and bloated. bup addresses this by using a rolling checksum, conceptually similar to the algorithm behind rsync, to split incoming data into content-defined chunks. Identical chunks that already exist anywhere in the backup store are not re-saved, giving bup strong deduplication both across separate backup runs and within a single large file. Unlike git, which typically requires periodic garbage collection and repacking to stay efficient, bup writes directly into packfiles as it goes, avoiding that maintenance overhead and keeping performance consistent even as the total backed-up dataset grows into the hundreds of gigabytes or more. Because bup's on-disk format is git-compatible, backup data can in principle be explored with standard git tools, which appeals to technically minded users who value transparency and portability over proprietary backup formats. Functionally, bup supports pushing backups to remote machines over SSH, mounting a backup archive as a browsable filesystem via FUSE, and indexing far more files and objects than vanilla git can practically handle - reportedly millions of filenames and very large total object counts. For users worried about long-term storage degradation, bup offers optional integration with par2 to add redundancy and allow recovery from bit rot or partial corruption. The project has no graphical interface and is aimed squarely at people comfortable with a terminal; its contribution model also differs from typical GitHub-centric open-source projects, since maintainers ask that patches and problem reports go through a mailing list rather than pull requests. As of recent releases (version 0.33.x), the project maintains continuous integration testing across Debian, FreeBSD, Ubuntu, and macOS, indicating it is still actively kept up rather than abandoned, even though its overall release cadence is modest and driven by volunteer effort rather than a company roadmap. There is no commercial version, paid tier, or vendor-hosted service associated with bup; it is entirely free software distributed under a mix of LGPL version 2 for the bulk of the codebase and a BSD-style license for a few specific files. This makes bup best suited to system administrators, self-hosters, and developers who want a lightweight, scriptable, highly space-efficient backup tool for servers, workstations, or virtual machine fleets, rather than casual users looking for a polished consumer backup app with cloud storage built in.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '65ebe3ad-b990-475e-b5d4-1e5a41eeb74f';

