-- ── C-Dogs SDL ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$C-Dogs SDL is a free, open-source, top-down run-and-gun game that revives Cyberdogs (1994) and C-Dogs (1997-2001), the original freeware DOS titles created by Swedish developer Ronny Wester. Wester released the C-Dogs source code publicly in 2002, and developers Jeremy Chin and Lucas Martin-King used it as the basis for an SDL-powered rewrite, released under the GPL-2.0-or-later license, that modernized the engine while keeping the original's fast, chaotic, overhead shoot-em-up gameplay intact. Players blast through top-down levels alone or with up to four people locally in co-operative or deathmatch modes, choosing from a roster of weapons and characters and fighting through more than 100 community-created campaigns built with the game's included map editor. Since its original SDL port, the project has continued to be maintained by its open-source community, migrating to SDL2 in 2015, adding support for classic Wolfenstein 3D and Spear of Destiny-style content in 2021, and shipping a significant 2.0.0 release in 2024. C-Dogs SDL runs natively on Windows, Linux, and macOS, and because it is entirely free and open source, it has become a staple recommendation on retro-gaming and open-source-game lists for players who want lightweight, nostalgic couch co-op action without any purchase or subscription.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2002, founded_year),
  company_size = COALESCE($q$Open-source community project (volunteer-maintained, no formal company)$q$, company_size),
  headquarters = COALESCE($q$N/A - distributed open-source project$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$C-Dogs SDL Review: The Free Open-Source Run-and-Gun Classic$q$, seo_title),
  seo_meta_description = COALESCE($q$C-Dogs SDL is a free open-source top-down run-and-gun game reviving the classic Cyberdogs/C-Dogs series. See features, co-op modes and modding support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$C-Dogs SDL is a free, open-source video game that keeps alive a lineage stretching back to the early 1990s. Its roots trace to Cyberdogs, a 1994 game created by Swedish developer Ronny Wester, whose follow-up work between 1997 and 2001 evolved into a freeware DOS title called C-Dogs: a fast, overhead run-and-gun shooter emphasizing chaotic local multiplayer combat. In 2002, Wester made the unusual and generous decision to release C-Dogs' source code publicly, which opened the door for other developers to preserve and extend the game long after the original DOS era had passed. Developers Jeremy Chin and Lucas Martin-King picked up that source release and rebuilt the game around the SDL (Simple DirectMedia Layer) library, producing C-Dogs SDL and releasing it under the GNU General Public License version 2 or later, with some portions under more permissive BSD-2-Clause terms, and its game data licensed under various free-culture terms such as CC0, CC-BY, and CC-BY-SA. This SDL rewrite preserved the essential feel of the original - fast, top-down, arcade-style shooting - while modernizing the underlying engine: it added high-resolution display support, smoother local multiplayer for up to four simultaneous players in both cooperative and deathmatch modes, enhanced graphics over the DOS original, and LAN multiplayer capability. The project has continued to evolve well beyond its initial release. In October 2015 it was substantially updated to use SDL2, the modernized successor to the original SDL library, improving compatibility with current operating systems and hardware. In August 2021, the game gained support for content in the style of classic first-person shooters Wolfenstein 3D and Spear of Destiny, broadening the kinds of community campaigns that could be built. And in February 2024, the project shipped a major 2.0.0 release, a sign that active development and community stewardship have continued for well over two decades since the original 2002 source release. One of C-Dogs SDL's defining features is its deep support for user-generated content: the game ships with a built-in campaign and map editor, and the community has produced more than 100 custom campaigns that dramatically extend the amount of content available beyond what shipped in the original release. This positions C-Dogs SDL as much as a modding platform as a standalone game, similar in spirit to how classic id Software titles fostered long-lived amateur level-design communities. The game runs natively on Windows, Linux, and macOS, and because both the code and (largely) the game data are free and openly licensed, there is no purchase price, subscription, or in-app monetization of any kind - it is simply downloaded and played. This makes C-Dogs SDL a frequent recommendation on lists of notable open-source and retro-style games, particularly for players who want simple, high-energy local co-op action reminiscent of arcade-era shooters, without needing a gaming console or paying anything to play. Its main limitations are the ones inherent to its genre and era: the visual style is intentionally retro rather than modern, its multiplayer focus is primarily local rather than built around robust online matchmaking, and because it is community-maintained rather than commercially developed, update cadence and long-term support depend on the continued interest of volunteer contributors rather than a company roadmap.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ca3f9df7-9a06-4cc2-93fc-2fe091154016';

