-- ── C3 ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$This profile refers to C3.ai (NYSE: AI), the publicly traded enterprise artificial-intelligence software company founded in 2009 by veteran enterprise-software entrepreneur Thomas Siebel (founder of Siebel Systems) - not any of the other, unrelated products that also go by the name 'C3.' The company was originally named C3 Energy and later C3 IoT before rebranding to C3.ai as it shifted from a narrow carbon- and energy-management focus toward a broader enterprise AI platform. C3.ai went public on the New York Stock Exchange in December 2020 and is headquartered in Redwood City, California, with roughly 900 to 1,200 employees depending on the reporting period. Its flagship offering is the C3 AI Platform, now marketed as the C3 Agentic AI Platform, a model-driven development environment that lets large enterprises and government agencies build, deploy, and operate AI and machine-learning applications at scale, alongside a library of prebuilt applications for use cases like predictive maintenance (Reliability), demand forecasting, inventory optimization, supply-chain sourcing, and process optimization. C3.ai sells primarily to large enterprises, government, and defense customers - including long-running relationships with the U.S. Air Force, Department of Defense, and industrial companies like Shell and Baker Hughes - rather than through self-serve signup, so pricing is customized per contract rather than published as fixed plans.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise / custom pricing (sales-led, contract-based, not self-serve)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing, not publicly listed; sold via direct enterprise and government sales$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$Large - approximately 900 to 1,200 employees, publicly traded on the NYSE under ticker AI$q$, company_size),
  headquarters = COALESCE($q$Redwood City, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$C3.ai Review: Enterprise AI Platform, Pricing and Products$q$, seo_title),
  seo_meta_description = COALESCE($q$C3.ai (NYSE: AI) is a publicly traded enterprise AI platform founded by Thomas Siebel. Learn what it does, who it serves, and how pricing works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Because the name 'C3' is shared by several unrelated products, it is worth being explicit up front: this profile covers C3.ai, the publicly traded enterprise artificial-intelligence software company listed on the New York Stock Exchange under the ticker symbol AI. It is not connected to the historical CacheFlow/Blue Coat lineage, nor to any other unrelated software tool that happens to use the name C3. C3.ai was founded in 2009 by Thomas Siebel, a well-known enterprise-software entrepreneur who previously founded and built Siebel Systems, the CRM company later acquired by Oracle. The company's naming and focus have shifted over time: it began under names reflecting a narrower mission around carbon management (the 'C3' name itself reportedly stood for concepts like carbon and 'measure, mitigate, and monetize'), was known briefly as C3 Energy and then C3IoT as its focus expanded to industrial Internet of Things applications, and eventually rebranded fully to C3.ai as artificial intelligence and machine learning became its central value proposition. C3.ai's initial public offering took place on December 9, 2020, when its shares more than doubled on the first day of trading, closing at a valuation that put the company's market capitalization near 8.9 billion dollars at the time. The company is headquartered at 1400 Seaport Boulevard in Redwood City, California, and employee counts reported across different sources in 2026 range from roughly 850 to about 1,200, reflecting normal variation in how headcount is measured and reported, alongside publicly discussed restructuring activity. C3.ai's core product is the C3 AI Platform, now marketed under names like the C3 Agentic AI Platform and C3 AI Studio, a model-driven, low-code development environment built specifically to let large organizations build, deploy, and operate AI and machine learning applications across massive, heterogeneous enterprise data sources. Beyond the platform itself, C3.ai sells a library of prebuilt, ready-to-deploy applications targeting specific high-value use cases: Reliability (predictive maintenance for industrial equipment), demand planning and forecasting, process optimization, inventory optimization, and supply-chain sourcing optimization, among others, plus more recent additions focused on generative AI and coding assistance (C3 Generative AI, C3 Code). The company's customer base skews heavily toward large enterprises and government or defense agencies rather than small or mid-sized businesses; publicly discussed relationships include the U.S. Air Force and the U.S. Department of Defense, as well as major industrial customers such as Shell and Baker Hughes in the energy sector. Because its buyers are large organizations with complex procurement processes, C3.ai does not offer self-serve signup or published pricing plans; instead, deployments are sold through direct enterprise sales, with pricing and contract terms negotiated on a per-customer basis, often tied to the scope of data integration, number of applications deployed, and length of contract. As a public company, C3.ai is also unusual among enterprise AI vendors in that it discloses financial results, growth metrics, and business risks in regular filings, giving prospective customers and researchers a level of transparency into its business performance that most privately held AI vendors do not provide. That transparency has also exposed the company to public scrutiny over its profitability and stock volatility since its 2020 IPO, a tradeoff of being a publicly traded, sales-led enterprise software business competing against both dedicated AI vendors and the AI offerings of large cloud hyperscalers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'affc9d1b-36d7-4584-8295-6495146e3435';

